from flask import Flask, session, request, redirect, url_for, render_template_string
import os
import hashlib
import secrets

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Simple user database (in production use a real database)
users = {
    'admin': hashlib.sha256('password'.encode()).hexdigest()
}

def generate_session_token():
    return secrets.token_urlsafe(32)

def verify_session_token(token):
    if not token:
        return False
    # In production, check against database or cache
    return True

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = hashlib.sha256(request.form['password'].encode()).hexdigest()
        
        if username in users and users[username] == password:
            session['user_id'] = username
            session['session_token'] = generate_session_token()
            return redirect(url_for('dashboard'))
        else:
            return 'Invalid credentials'
    
    return render_template_string('''
        <form method="post">
            Username: <input type="text" name="username"><br>
            Password: <input type="password" name="password"><br>
            <input type="submit" value="Login">
        </form>
    ''')

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session or not verify_session_token(session.get('session_token')):
        return redirect(url_for('login'))
    
    return f'Welcome {session["user_id"]}! <a href="/logout">Logout</a>'

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

if __name__ == '__main__':
    app.run(debug=False)